using UnityEngine;
using Climbing;

public class GroundGapInspector
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        Transform root = pm.transform.root;
        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();

        string report = $"--- Air Gap Check ---\n";
        report += $"Root: {root.name} at {root.position}\n";
        report += $"Model: {pm.name} LocalPos: {pm.transform.localPosition}\n";

        if (col != null) {
            float bottomY = pm.transform.position.y + col.center.y - (col.height / 2f);
            report += $"Collider Bottom World Y: {bottomY}\n";

            RaycastHit hit;
            if (Physics.Raycast(pm.transform.position + col.center, Vector3.down, out hit, 10f)) {
                report += $"Ground found: {hit.collider.name} at Y: {hit.point.y}\n";
                report += $"Gap from Collider Bottom to Ground: {bottomY - hit.point.y} units\n";
            } else {
                report += "No ground found below collider center!\n";
            }
        }

        return report;
    }
}
